// Parse incoming Slack Events API and Interactivity payloads.
const rawBody = $input.first().json.body || $input.first().json;
let body = rawBody;

if (typeof rawBody.payload === 'string') {
  try { body = JSON.parse(rawBody.payload); } catch (e) { body = rawBody; }
} else if (rawBody.payload && typeof rawBody.payload === 'object') {
  body = rawBody.payload;
}

if (body.type === 'url_verification') {
  return [{ json: { routeType: 'challenge', challenge: body.challenge } }];
}

if (body.type === 'block_actions') {
  const action = (body.actions || [])[0] || {};
  return [{ json: {
    routeType: 'event',
    interactionType: 'block_actions',
    actionId: action.action_id || '',
    triggerId: body.trigger_id || '',
    userId: body.user?.id || '',
    channelId: body.channel?.id || body.container?.channel_id || '',
    text: '',
    messageType: 'interaction',
    fileUrl: '',
    fileName: '',
    fileMimeType: '',
    allFiles: [],
  } }];
}

if (body.type === 'view_submission') {
  const meta = (() => { try { return JSON.parse(body.view?.private_metadata || '{}'); } catch (e) { return {}; } })();
  const values = body.view?.state?.values || {};
  function field(blockId, actionId) {
    const item = values[blockId]?.[actionId] || {};
    if (Object.prototype.hasOwnProperty.call(item, 'value')) return item.value;
    if (item.selected_option) return item.selected_option.value;
    if (item.selected_date) return item.selected_date;
    return '';
  }
  return [{ json: {
    routeType: 'event',
    interactionType: 'view_submission',
    callbackId: body.view?.callback_id || '',
    userId: body.user?.id || meta.userId || '',
    channelId: meta.channelId || '',
    messageType: 'modal_submission',
    modalValues: {
      client_name: field('client_name_block', 'client_name'),
      company_name: field('company_name_block', 'company_name'),
      email: field('email_block', 'email'),
      phone: field('phone_block', 'phone'),
      address: field('address_block', 'address'),
      project_name: field('project_name_block', 'project_name'),
      city: field('city_block', 'city'),
      country: field('country_block', 'country'),
      due_date: field('due_date_block', 'due_date'),
      service_option: field('service_option_block', 'service_option'),
      margin_percent: field('margin_block', 'margin_percent'),
      payment_terms_text: field('payment_terms_block', 'payment_terms_text'),
      subject: field('subject_block', 'subject'),
    },
  } }];
}

if (body.type !== 'event_callback' || !body.event) {
  return [{ json: { routeType: 'skip' } }];
}

const event = body.event;
if (event.bot_id) {
  return [{ json: { routeType: 'skip' } }];
}
if (event.subtype && event.subtype !== 'file_share') {
  return [{ json: { routeType: 'skip' } }];
}
if (event.channel_type && event.channel_type !== 'im') {
  return [{ json: { routeType: 'skip' } }];
}

const files = event.files || [];
let messageType = 'text';
let fileUrl = '';
let fileName = '';
let fileMimeType = '';
let allFiles = [];

if (files.length > 0) {
  const file = files[0];
  fileUrl = file.url_private_download || file.url_private || '';
  fileName = file.name || 'file';
  fileMimeType = file.mimetype || '';
  allFiles = files.map(f => ({
    url: f.url_private_download || f.url_private || '',
    name: f.name || 'file',
    mimetype: f.mimetype || '',
  }));
  messageType = fileMimeType.startsWith('image/') ? 'image' : 'document';
}

return [{ json: {
  routeType: 'event',
  interactionType: 'message',
  userId: event.user || '',
  channelId: event.channel || '',
  text: event.text || '',
  messageType,
  fileUrl,
  fileName,
  fileMimeType,
  allFiles,
} }];

// ============================================================
// Layer 1: Slack-specific conversation state machine
// Collects BOQ/spec via DM, then opens a modal for structured details.
// On completion, outputs execute_pipeline with file URLs.
// ============================================================

const SLACK_BOT_TOKEN = process.env.SLACK_BOT_TOKEN || '';

const input = $input.first().json;
if (input.routeType === 'skip') {
  return [{ json: { action: 'no_op' } }];
}

const {
  userId, channelId, text: rawText, messageType, fileUrl, fileName,
  fileMimeType, allFiles, interactionType, actionId, triggerId,
  callbackId, modalValues,
} = input;
const text = (rawText || '').trim();
const textLower = text.toLowerCase();

const fs = require('fs');
const STATE_FILE = '/home/node/.n8n/slack_conversations.json';
function loadConvs() { try { return JSON.parse(fs.readFileSync(STATE_FILE, 'utf8')); } catch(e) { return {}; } }
function saveConvs(c) { fs.writeFileSync(STATE_FILE, JSON.stringify(c), 'utf8'); }
function clean(v) { return String(v || '').trim(); }
function isEmail(v) { return !v || /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v); }
function todayIso() { return new Date().toISOString().split('T')[0]; }
function isCancelCommand(v) { return ['cancel', 'stop', 'restart'].includes(String(v || '').trim().toLowerCase()); }
function resetConversation(channelId) { return { state: 'new', channel_id: channelId || undefined }; }

function detailsButton() {
  return [{
    type: 'actions',
    elements: [{
      type: 'button',
      text: { type: 'plain_text', text: 'Enter quotation details' },
      style: 'primary',
      action_id: 'open_quotation_details_modal',
    }],
  }];
}

function quotationModal(conv, userId, channelId) {
  return {
    type: 'modal',
    callback_id: 'quotation_details_modal',
    private_metadata: JSON.stringify({ userId, channelId }),
    title: { type: 'plain_text', text: 'Quotation details' },
    submit: { type: 'plain_text', text: 'Submit' },
    close: { type: 'plain_text', text: 'Cancel' },
    blocks: [
      { type: 'input', block_id: 'client_name_block', label: { type: 'plain_text', text: 'Client name' }, element: { type: 'plain_text_input', action_id: 'client_name', placeholder: { type: 'plain_text', text: 'e.g. Ahmed Khan' }, max_length: 120 } },
      { type: 'input', block_id: 'company_name_block', label: { type: 'plain_text', text: 'Company name' }, element: { type: 'plain_text_input', action_id: 'company_name', placeholder: { type: 'plain_text', text: 'e.g. ACME Trading' }, max_length: 160 } },
      { type: 'input', block_id: 'email_block', optional: true, label: { type: 'plain_text', text: 'Email' }, element: { type: 'email_text_input', action_id: 'email', placeholder: { type: 'plain_text', text: 'name@example.com' } } },
      { type: 'input', block_id: 'phone_block', optional: true, label: { type: 'plain_text', text: 'Phone' }, element: { type: 'plain_text_input', action_id: 'phone', placeholder: { type: 'plain_text', text: '+966...' }, max_length: 40 } },
      { type: 'input', block_id: 'address_block', optional: true, label: { type: 'plain_text', text: 'Address' }, element: { type: 'plain_text_input', action_id: 'address', placeholder: { type: 'plain_text', text: 'Optional' }, max_length: 220 } },
      { type: 'divider' },
      { type: 'input', block_id: 'project_name_block', label: { type: 'plain_text', text: 'Project name' }, element: { type: 'plain_text_input', action_id: 'project_name', placeholder: { type: 'plain_text', text: 'e.g. Riyadh Office Tower' }, max_length: 180 } },
      { type: 'input', block_id: 'city_block', label: { type: 'plain_text', text: 'City' }, element: { type: 'plain_text_input', action_id: 'city', initial_value: 'Riyadh', max_length: 100 } },
      { type: 'input', block_id: 'country_block', label: { type: 'plain_text', text: 'Country' }, element: { type: 'plain_text_input', action_id: 'country', initial_value: 'KSA', max_length: 100 } },
      { type: 'input', block_id: 'due_date_block', label: { type: 'plain_text', text: 'Due date' }, element: { type: 'datepicker', action_id: 'due_date', initial_date: todayIso(), placeholder: { type: 'plain_text', text: 'Select date' } } },
      { type: 'divider' },
      { type: 'input', block_id: 'service_option_block', label: { type: 'plain_text', text: 'Service option' }, element: { type: 'static_select', action_id: 'service_option', initial_option: { text: { type: 'plain_text', text: 'Supply & Install' }, value: '2' }, options: [
        { text: { type: 'plain_text', text: 'Supply Only' }, value: '1' },
        { text: { type: 'plain_text', text: 'Supply & Install' }, value: '2' },
        { text: { type: 'plain_text', text: 'Supply, Install & Commission' }, value: '3' },
      ] } },
      { type: 'input', block_id: 'margin_block', label: { type: 'plain_text', text: 'Margin percent' }, element: { type: 'number_input', action_id: 'margin_percent', is_decimal_allowed: true, initial_value: '0', min_value: '0', max_value: '100' } },
      { type: 'input', block_id: 'payment_terms_block', optional: true, label: { type: 'plain_text', text: 'Payment terms' }, element: { type: 'plain_text_input', action_id: 'payment_terms_text', multiline: true, placeholder: { type: 'plain_text', text: 'Optional payment terms' }, max_length: 1200 } },
      { type: 'input', block_id: 'subject_block', optional: true, label: { type: 'plain_text', text: 'Quotation subject' }, element: { type: 'plain_text_input', action_id: 'subject', placeholder: { type: 'plain_text', text: 'Optional subject line' }, max_length: 180 } },
    ],
  };
}

function validateDetails(v) {
  const errors = [];
  const required = [
    ['client_name', 'Client name'], ['company_name', 'Company name'],
    ['project_name', 'Project name'], ['city', 'City'], ['country', 'Country'], ['due_date', 'Due date'],
  ];
  for (const [key, label] of required) {
    if (!clean(v[key])) errors.push(label + ' is required.');
  }
  if (v.email && !isEmail(clean(v.email))) errors.push('Email must be valid.');
  if (v.due_date && !/^\d{4}-\d{2}-\d{2}$/.test(clean(v.due_date))) errors.push('Due date must be YYYY-MM-DD.');
  const svc = parseInt(v.service_option, 10);
  if (![1, 2, 3].includes(svc)) errors.push('Service option is invalid.');
  const margin = Number(v.margin_percent);
  if (!Number.isFinite(margin) || margin < 0 || margin > 100) errors.push('Margin must be between 0 and 100.');
  return errors;
}

const allConvs = loadConvs();
if (!allConvs[userId]) allConvs[userId] = { state: 'new' };
const conv = allConvs[userId];
if (channelId) conv.channel_id = channelId;
const effectiveChannelId = channelId || conv.channel_id;
const state = conv.state;

let action = 'no_op';
let payload = {};

if (messageType === 'text' && isCancelCommand(textLower)) {
  if (state === 'executing') {
    action = 'send_message';
    payload = { text: 'Your quotation is already being generated, so it cannot be cancelled now. I will send the DOCX here when it is ready, or an error message if generation fails.' };
  } else if (state === 'new' || state === 'awaiting_confirm') {
    allConvs[userId] = resetConversation(effectiveChannelId);
    action = 'send_message';
    payload = { text: 'There is no active quotation request to cancel. Send me a message anytime to start a new one.' };
  } else {
    allConvs[userId] = resetConversation(effectiveChannelId);
    action = 'send_message';
    payload = { text: 'Quotation request cancelled. Send me a message anytime to start again.' };
  }
  saveConvs(allConvs);
  return [{ json: { action, payload, channelId: effectiveChannelId, config: { SLACK_BOT_TOKEN } } }];
}

if (interactionType === 'block_actions' && actionId === 'open_quotation_details_modal') {
  if (!conv.spec_file_url) {
    action = 'send_message';
    payload = { text: 'Please send your Specification PDF before entering quotation details.' };
  } else {
    action = 'open_modal';
    payload = { trigger_id: triggerId, view: quotationModal(conv, userId, effectiveChannelId) };
    conv.state = 'awaiting_modal_submission';
  }
  saveConvs(allConvs);
  return [{ json: { action, payload, channelId: effectiveChannelId, config: { SLACK_BOT_TOKEN } } }];
}

if (interactionType === 'view_submission' && callbackId === 'quotation_details_modal') {
  if (!conv.spec_file_url || !['awaiting_modal_open', 'awaiting_modal_submission'].includes(conv.state)) {
    allConvs[userId] = resetConversation(effectiveChannelId);
    action = 'send_message';
    payload = { text: 'This quotation request is no longer active. Send me a message anytime to start a new one.' };
    saveConvs(allConvs);
    return [{ json: { action, payload, channelId: effectiveChannelId, config: { SLACK_BOT_TOKEN } } }];
  }
  const v = modalValues || {};
  const errors = validateDetails(v);
  if (errors.length) {
    action = 'send_message';
    payload = { text: 'Some details need attention:\n- ' + errors.join('\n- ') + '\n\nUse the button below to submit the corrected details.', blocks: detailsButton() };
    conv.state = 'awaiting_modal_open';
  } else {
    conv.client_data = {
      name: clean(v.client_name),
      company_name: clean(v.company_name),
      email: clean(v.email) || null,
      phone: clean(v.phone) || null,
      address: clean(v.address) || null,
    };
    conv.project_data = {
      project_name: clean(v.project_name),
      city: clean(v.city),
      country: clean(v.country),
      due_date: clean(v.due_date),
    };
    conv.quotation_config = {
      service_option: parseInt(v.service_option, 10),
      margin_percent: Number(v.margin_percent),
      payment_terms_text: clean(v.payment_terms_text) || null,
      subject: clean(v.subject) || null,
    };
    conv.state = 'executing';
    action = 'execute_pipeline';
    payload = { userId, channelId: effectiveChannelId, conversation: JSON.parse(JSON.stringify(conv)) };
  }
  saveConvs(allConvs);
  return [{ json: { action, payload, channelId: effectiveChannelId, config: { SLACK_BOT_TOKEN } } }];
}

switch (state) {
  case 'new': {
    action = 'send_message';
    payload = { text: 'Welcome! Would you like to generate a quotation?\n\nReply *1* for Yes\nReply *2* for No\n\nYou can send *cancel* anytime before generation starts.' };
    conv.state = 'awaiting_confirm';
    break;
  }
  case 'awaiting_confirm': {
    if (text === '1' || textLower === 'yes') {
      action = 'send_message';
      payload = { text: 'Please send your *BOQ file*.\n\nAccepted formats:\n- Excel (.xlsx)\n- PDF (.pdf)\n- Images (you can send multiple)\n\nSend *cancel* to cancel this request.' };
      conv.state = 'awaiting_boq';
    } else if (text === '2' || textLower === 'no') {
      action = 'send_message';
      payload = { text: 'No problem! Send me a message anytime to start.' };
      conv.state = 'new';
    } else {
      action = 'send_message';
      payload = { text: 'Reply *1* for Yes or *2* for No. You can also send *cancel* to reset.' };
    }
    break;
  }
  case 'awaiting_boq': {
    if (messageType === 'document') {
      const isXlsx = (fileMimeType||'').includes('spreadsheet') || (fileMimeType||'').includes('excel') || (fileName||'').toLowerCase().endsWith('.xlsx');
      const isPdf = fileMimeType === 'application/pdf' || (fileName||'').toLowerCase().endsWith('.pdf');
      if (isXlsx || isPdf) {
        conv.boq_media_type = isPdf ? 'pdf' : 'xlsx';
        conv.boq_file_url = fileUrl;
        conv.boq_filename = fileName || (isPdf ? 'boq.pdf' : 'boq.xlsx');
        conv.boq_mime_type = fileMimeType;
        action = 'send_message';
        payload = { text: 'BOQ file received.\n\nNow send your *Specification file* (PDF only). Send *cancel* to cancel this request.' };
        conv.state = 'awaiting_spec';
      } else {
        action = 'send_message';
        payload = { text: 'Unsupported format. Please send Excel (.xlsx) or PDF (.pdf).' };
      }
    } else if (messageType === 'image') {
      conv.boq_images = (allFiles||[]).map((f,i) => ({ url: f.url, name: f.name||('boq_image_'+(i+1)+'.jpg'), mimetype: f.mimetype||'image/jpeg' }));
      conv.boq_media_type = 'images';
      action = 'send_message';
      payload = { text: conv.boq_images.length + ' image(s) received. Send more images, reply *done*, or send *cancel* to cancel this request.' };
      conv.state = 'collecting_boq_images';
    } else {
      action = 'send_message';
      payload = { text: 'Please send a BOQ file (Excel, PDF, or images).' };
    }
    break;
  }
  case 'collecting_boq_images': {
    if (messageType === 'image') {
      if (!conv.boq_images) conv.boq_images = [];
      (allFiles||[]).forEach(f => { conv.boq_images.push({ url: f.url, name: f.name, mimetype: f.mimetype||'image/jpeg' }); });
      action = 'send_message';
      payload = { text: conv.boq_images.length + ' image(s) total. Send more images, reply *done*, or send *cancel* to cancel this request.' };
    } else if (textLower === 'done') {
      action = 'send_message';
      payload = { text: (conv.boq_images||[]).length + ' BOQ image(s) saved.\n\nNow send your *Specification file* (PDF only). Send *cancel* to cancel this request.' };
      conv.state = 'awaiting_spec';
    } else {
      action = 'send_message';
      payload = { text: 'Send an image, reply *done*, or send *cancel* to cancel this request.' };
    }
    break;
  }
  case 'awaiting_spec': {
    if (messageType === 'document' && (fileMimeType === 'application/pdf' || (fileName||'').toLowerCase().endsWith('.pdf'))) {
      conv.spec_file_url = fileUrl;
      conv.spec_filename = fileName || 'specification.pdf';
      action = 'send_message';
      payload = { text: 'Specification received. Use the button below to enter all required client, project, and quotation details in one form. After you submit the form, generation will start and the request cannot be cancelled.\n\nYou can still send *cancel* now if you want to restart before submitting details.', blocks: detailsButton() };
      conv.state = 'awaiting_modal_open';
    } else {
      action = 'send_message';
      payload = { text: 'Please send a PDF file for the specification, or send *cancel* to cancel this request.' };
    }
    break;
  }
  case 'awaiting_modal_open':
  case 'awaiting_modal_submission': {
    action = 'send_message';
    payload = { text: 'I already sent the details button above. Please press *Enter quotation details* to continue, or send *cancel* to cancel this request.' };
    conv.state = state === 'awaiting_modal_submission' ? 'awaiting_modal_submission' : 'awaiting_modal_open';
    break;
  }
  case 'executing': {
    action = 'send_message';
    payload = { text: 'Your quotation is already being generated, so it cannot be cancelled now. I will send the DOCX here when it is ready, or an error message if generation fails.' };
    break;
  }
  default: {
    conv.state = 'awaiting_confirm';
    action = 'send_message';
    payload = { text: 'Welcome! Would you like to generate a quotation?\n\nReply *1* for Yes\nReply *2* for No\n\nYou can send *cancel* anytime before generation starts.' };
    break;
  }
}

saveConvs(allConvs);
return [{ json: { action, payload, channelId: effectiveChannelId, config: { SLACK_BOT_TOKEN } } }];

// Download from Slack, login, upload to backend.
// Uses require('https'/'http') for binary, this.helpers.httpRequest for JSON.
const https = require('https');
const http = require('http');

// Manual URL parser (no URL/url module - both break in n8n sandbox)
function parseUrl(s) {
  const m = s.match(/^(https?):\/\/([^\/:]+)(?::(\d+))?(\/.*)$/);
  if (!m) return { protocol: 'https:', hostname: s, port: null, path: '/' };
  return { protocol: m[1] + ':', hostname: m[2], port: m[3] || null, path: m[4] || '/' };
}

const SLACK_BOT_TOKEN = process.env.SLACK_BOT_TOKEN || '';
const BACKEND_API_URL = process.env.BACKEND_API_URL || 'http://172.17.0.1:3001';
const TENANT_SLUG = process.env.RAGM_TENANT_SLUG || 'acme';
const LOGIN_EMAIL = process.env.RAGM_LOGIN_EMAIL || 'admin@acme.com';
const LOGIN_PASSWORD = process.env.RAGM_LOGIN_PASSWORD || 'admin123';
const CALLBACK_ROUTER_URL = process.env.CALLBACK_ROUTER_URL || 'http://172.17.0.1:5678/webhook/pipeline-callback-router';

const input = $input.first().json;
const payload = input.payload || {};
const userId = payload.userId;
const channelId = payload.channelId;
const conv = payload.conversation || {};

// JSON-only calls via n8n helper (no binary IPC issue)
const sendMsg = async (text) => {
  await this.helpers.httpRequest({
    method: 'POST', url: 'https://slack.com/api/chat.postMessage',
    headers: { Authorization: 'Bearer ' + SLACK_BOT_TOKEN, 'Content-Type': 'application/json' },
    body: { channel: channelId, text }, json: true, timeout: 10000,
  });
};

// Binary download via native https (avoids Task Runner IPC hang)
const downloadFile = (fileUrl) => new Promise((resolve, reject) => {
  const opts = parseUrl(fileUrl);
  const mod = opts.protocol === 'https:' ? https : http;
  const req = mod.get({ hostname: opts.hostname, port: opts.port, path: opts.path, headers: { Authorization: 'Bearer ' + SLACK_BOT_TOKEN } }, (res) => {
    if (res.statusCode === 301 || res.statusCode === 302) {
      downloadFile(res.headers.location).then(resolve).catch(reject);
      return;
    }
    if (res.statusCode !== 200) { reject(new Error('Download HTTP ' + res.statusCode)); return; }
    const chunks = [];
    res.on('data', c => chunks.push(c));
    res.on('end', () => resolve(Buffer.concat(chunks)));
    res.on('error', reject);
  });
  req.on('error', reject);
  req.setTimeout(60000, () => { req.destroy(); reject(new Error('Download timeout')); });
});

// Multipart upload via native http (binary body, no IPC)
const uploadMultipart = (uploadUrl, headers, body) => new Promise((resolve, reject) => {
  const parsed = parseUrl(uploadUrl);
  const req = http.request({ hostname: parsed.hostname, port: parsed.port, path: parsed.path, method: 'POST', headers }, (res) => {
    const chunks = [];
    res.on('data', c => chunks.push(c));
    res.on('end', () => {
      const text = Buffer.concat(chunks).toString();
      if (res.statusCode >= 400) { reject(new Error('Upload HTTP ' + res.statusCode + ': ' + text)); return; }
      try { resolve(JSON.parse(text)); } catch(e) { resolve(text); }
    });
  });
  req.on('error', reject);
  req.setTimeout(120000, () => { req.destroy(); reject(new Error('Upload timeout')); });
  req.write(body);
  req.end();
});

try {
  const serviceLabels = { 1: 'Supply Only', 2: 'Supply & Install', 3: 'Supply, Install & Commission' };
  const submittedSummary = [
    'Details submitted successfully.',
    '',
    '*Client:* ' + ((conv.client_data || {}).name || 'N/A'),
    '*Company:* ' + ((conv.client_data || {}).company_name || 'N/A'),
    '*Project:* ' + ((conv.project_data || {}).project_name || 'N/A'),
    '*Location:* ' + [((conv.project_data || {}).city || ''), ((conv.project_data || {}).country || '')].filter(Boolean).join(', '),
    '*Due date:* ' + ((conv.project_data || {}).due_date || 'N/A'),
    '*Service:* ' + (serviceLabels[(conv.quotation_config || {}).service_option] || 'N/A'),
    '*Margin:* ' + String((conv.quotation_config || {}).margin_percent ?? 0) + '%',
    '',
    'I am generating your quotation now and will send the DOCX here when it is ready.',
  ].join('\n');
  await sendMsg(submittedSummary);

  // 1) Download files from Slack via native https
  let boqBuffer, boqName, boqMime;
  if (conv.boq_media_type === 'images') {
    const first = (conv.boq_images || [])[0];
    if (!first || !first.url) throw new Error('No BOQ image URL');
    boqBuffer = await downloadFile(first.url);
    boqName = first.name || 'boq_image.jpg';
    boqMime = first.mimetype || 'image/jpeg';
  } else {
    if (!conv.boq_file_url) throw new Error('No BOQ file URL');
    boqBuffer = await downloadFile(conv.boq_file_url);
    boqName = conv.boq_filename || 'boq.xlsx';
    boqMime = conv.boq_mime_type || 'application/octet-stream';
  }
  if (!conv.spec_file_url) throw new Error('No spec file URL');
  const specBuffer = await downloadFile(conv.spec_file_url);
  const specName = conv.spec_filename || 'specification.pdf';

  // 2) Login via n8n helper (JSON only)
  const loginResp = await this.helpers.httpRequest({
    method: 'POST', url: BACKEND_API_URL + '/api/auth/login',
    headers: { 'Content-Type': 'application/json', 'x-tenant-slug': TENANT_SLUG },
    body: { email: LOGIN_EMAIL, password: LOGIN_PASSWORD },
    json: true, timeout: 15000,
  });
  if (!loginResp || !loginResp.access_token) throw new Error('Login failed');
  const token = loginResp.access_token;

  // 3) Build multipart and upload via native http
  const boundary = '----n8nSlack' + Date.now();
  const CRLF = '\r\n';
  const fp = (n, v) => Buffer.from('--' + boundary + CRLF + 'Content-Disposition: form-data; name="' + n + '"' + CRLF + CRLF + v + CRLF);
  const ff = (n, fn, ct, d) => [Buffer.from('--' + boundary + CRLF + 'Content-Disposition: form-data; name="' + n + '"; filename="' + fn + '"' + CRLF + 'Content-Type: ' + ct + CRLF + CRLF), d, Buffer.from(CRLF)];

  const parts = [];
  parts.push(...ff('boq_file', boqName, boqMime, boqBuffer));
  parts.push(...ff('spec_file', specName, 'application/pdf', specBuffer));
  parts.push(fp('source_platform', 'slack'));
  parts.push(fp('platform_reply_info', JSON.stringify({ channel_id: channelId, user_id: userId, bot_token: SLACK_BOT_TOKEN })));
  parts.push(fp('client_data', JSON.stringify(conv.client_data || {})));
  parts.push(fp('project_data', JSON.stringify(conv.project_data || {})));
  parts.push(fp('quotation_config', JSON.stringify(conv.quotation_config || {})));
  parts.push(fp('boq_media_type', conv.boq_media_type || 'xlsx'));
  parts.push(fp('callback_url', CALLBACK_ROUTER_URL));
  parts.push(Buffer.from('--' + boundary + '--' + CRLF));
  const body = Buffer.concat(parts);

  const result = await uploadMultipart(
    BACKEND_API_URL + '/api/integrations/generic/quotation/start',
    { Authorization: 'Bearer ' + token, 'x-tenant-slug': TENANT_SLUG, 'Content-Type': 'multipart/form-data; boundary=' + boundary, 'Content-Length': String(body.length) },
    body
  );

  return [{ json: { ok: true, project_id: result.project_id, pipeline_run_id: result.pipeline_run_id } }];

} catch (error) {
  const fs = require('fs');
  try {
    const c = JSON.parse(fs.readFileSync('/home/node/.n8n/slack_conversations.json','utf8'));
    if (c[userId]) { c[userId] = { state: 'new' }; fs.writeFileSync('/home/node/.n8n/slack_conversations.json', JSON.stringify(c), 'utf8'); }
  } catch(e) {}
  await sendMsg('Could not start quotation: ' + (error.message || String(error)) + '\n\nPlease try again.');
  return [{ json: { failed: true, error: error.message } }];
}
